VALUES
  ('aboriginal-f0899a01-moex-00117', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-113-d1a761c9', 'sub-aboriginal-f0899a01-03', NULL, 'single_choice', '依司法院解釋意旨，下列何者係為支應國家一般性財政需求，而非因特定政策用途而對人民強制徵收 之金錢給付義務？', '["使用牌照稅", "容器回收清除處理費", "空氣污染防制費", "汽車燃料使用費"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:32+00:00", "source_pdf_sha1": "0040a001dc59", "answer_pdf_sha1": "95f616d7c0ce", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "507", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00118', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-113-d1a761c9', 'sub-aboriginal-f0899a01-03', NULL, 'single_choice', '關於行政組織之敘述，下列何者錯誤？', '["獨立機關係指依據法律獨立行使職權，自主運作，除法律另有規定外，不受其他機關指揮監督之合 議制機關", "受託行使公權力之個人或團體，於委託範圍內，視為行政機關", "機構係指基於組織之業務分工，於機關內部設立之組織", "為執行特定公共事務，於國家及地方自治團體以外，得設具公法性質之行政法人"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:32+00:00", "source_pdf_sha1": "0040a001dc59", "answer_pdf_sha1": "95f616d7c0ce", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "507", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00119', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-113-d1a761c9', 'sub-aboriginal-f0899a01-03', NULL, 'single_choice', '關於地方自治「委辦行政」之敘述，下列何者正確？', '["上級政府僅得為適法性監督", "委辦係僅得依法律，在上級政府指揮監督下，執行上級政府交付辦理之非屬該團體事務", "上級政府亦得為合目的性監督", "「委辦行政」之責任係由上級政府負行政執行成敗責任，地方自治團體不負其行政執行責任之事項"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:32+00:00", "source_pdf_sha1": "0040a001dc59", "answer_pdf_sha1": "95f616d7c0ce", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "507", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00120', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-113-d1a761c9', 'sub-aboriginal-f0899a01-03', NULL, 'single_choice', '關於公法人之敘述，下列何者正確？', '["依行政法人法規定，工業技術研究院為公法人", "原住民族部落在原住民族基本法制定後自動轉變成公法人", "依地方制度法規定，臺北市為公法人", "依大學法之規定，國立大學為公法人"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:32+00:00", "source_pdf_sha1": "0040a001dc59", "answer_pdf_sha1": "95f616d7c0ce", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "507", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00121', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-113-d1a761c9', 'sub-aboriginal-f0899a01-03', NULL, 'single_choice', '依行政程序法規定，行政機關執行職務得向其他機關請求協助之敘述，下列何者錯誤？', '["因法律上之原因，不能獨自執行職務者，得請求之", "可請求有隸屬關係之機關為協助", "由被請求機關協助執行，顯較經濟者，得請求之", "執行職務所必要認定之事實，不能獨自調查者，得請求之"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:32+00:00", "source_pdf_sha1": "0040a001dc59", "answer_pdf_sha1": "95f616d7c0ce", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "507", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00122', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-113-d1a761c9', 'sub-aboriginal-f0899a01-03', NULL, 'single_choice', '關於行政委託與行政助手之敘述，下列何者錯誤？', '["在行政委託下，公權力有所轉移；行政助手則無", "在行政委託下，受委託機關有名義及執行上之獨立性；行政助手則無", "行政助手受行政機關指示執行事務；受委託者則僅受事後監督", "行政助手造成人民權利損害時，不適用國家賠償法；行政委託則國家應負賠償責任"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:32+00:00", "source_pdf_sha1": "0040a001dc59", "answer_pdf_sha1": "95f616d7c0ce", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "507", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00123', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-113-d1a761c9', 'sub-aboriginal-f0899a01-03', NULL, 'single_choice', '行政機關執行職務時應遵守行政慣例，與下列何種行政法一般原則直接相關？', '["法律優位原則", "信賴保護原則", "平等原則", "不當聯結禁止原則"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:32+00:00", "source_pdf_sha1": "0040a001dc59", "answer_pdf_sha1": "95f616d7c0ce", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "507", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00124', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-113-d1a761c9', 'sub-aboriginal-f0899a01-03', NULL, 'single_choice', '關於公務員法規之適用，下列何者錯誤？', '["受有俸給之文武職公務員及公營事業機構純勞工以外之人員，除中央研究院未兼任行政職務之研究 人員、研究技術人員外，均有公務員服務法之適用", "公立學校校長基於教育專業自主原則，故無公務人員行政中立法之適用", "公立學校未兼行政職務之專任教師無公務人員保障法之適用", "政務官無公務人員任用法之適用"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:32+00:00", "source_pdf_sha1": "0040a001dc59", "answer_pdf_sha1": "95f616d7c0ce", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "507", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00125', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-113-d1a761c9', 'sub-aboriginal-f0899a01-03', NULL, 'single_choice', '下列何者為附負擔之行政處分？', '["申請新臺幣1萬元補助費，但核准發給新臺幣5,000元", "申請週日10時至18時舉行集會遊行，但核准為週日12時至18時舉行", "核發某工廠設廠許可，但要求每年必須支付一定數額回饋金給當地居民", "核發某餐廳營業許可，但要求必須設置隔音設備始得開始營業"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:32+00:00", "source_pdf_sha1": "0040a001dc59", "answer_pdf_sha1": "95f616d7c0ce", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "507", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00126', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-113-d1a761c9', 'sub-aboriginal-f0899a01-03', NULL, 'single_choice', '關於公務人員申訴、再申訴之救濟程序，下列敘述何者錯誤？', '["申訴之提起必須是公務人員服務機關所為之管理措施或有關工作條件之處置違法，致侵害公務人員 權益", "申訴應向服務機關為之，再申訴應向公務人員保障暨培訓委員會為之", "公務人員離職後，接獲原服務機關之管理措施或處置者，亦得提起申訴、再申訴", "應提起復審之事件，公務人員誤提申訴者，申訴受理機關應移由原處分機關依復審程序處理"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:32+00:00", "source_pdf_sha1": "0040a001dc59", "answer_pdf_sha1": "95f616d7c0ce", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "507", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL)
